changeSet.sql:
CREATE OR REPLACE FUNCTION generate_api_key() RETURNS TRIGGER AS $$
BEGIN
    IF NEW.api_key IS NULL THEN
        NEW.api_key := replace(CAST(gen_random_uuid() AS text), '-', '');
        NEW.enable_api_key := true;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS user_account_api_key_trg ON user_account;
CREATE TRIGGER user_account_api_key_trg
BEFORE INSERT ON user_account
FOR EACH ROW EXECUTE PROCEDURE generate_api_key();

CREATE OR REPLACE TRIGGER user_account_api_key_trg
BEFORE INSERT ON user_account
FOR EACH ROW
BEGIN
    IF :NEW.api_key IS NULL THEN
        :NEW.api_key := lower(rawtohex(sys_guid()));
        :NEW.enable_api_key := 1;
    END IF;
END;
